using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summariser that scores sentences by normalised word-frequency
/// and returns the top-N sentences in their original document order.
/// </summary>
public partial class ExtractiveSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","me","my","myself",
        "we","our","ours","ourselves","you","your","yours","yourself",
        "yourselves","he","him","his","himself","she","her","hers","herself",
        "it","its","itself","they","them","their","theirs","themselves",
        "what","which","who","whom","this","that","these","those","am",
        "been","being","have","has","had","having","do","does","did","doing",
        "to","from","up","down","in","out","on","off","over","under","again",
        "further","then","once","here","there","when","where","why","how",
        "all","both","each","few","more","most","other","some","such","no",
        "nor","not","only","own","same","so","than","too","very","s","t",
        "just","don","now","of","at","by","for","with","about","between",
        "through","during","before","after","above","below","into"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitSentences(documentText);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, idx) => (Index: idx, Sentence: s, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;
                freq[word] = freq.TryGetValue(word, out var count) ? count + 1 : 1;
            }
        }

        if (freq.Count == 0)
            return [];

        var maxFreq = (double)freq.Values.Max();
        return freq.ToDictionary(kv => kv.Key, kv => kv.Value / maxFreq, StringComparer.OrdinalIgnoreCase);
    }

    private static double ScoreSentence(string sentence, Dictionary<string, double> wordFrequencies)
    {
        var words = Tokenize(sentence);
        if (words.Count == 0) return 0;

        var score = words
            .Where(w => !StopWords.Contains(w) && w.Length >= 2)
            .Sum(w => wordFrequencies.TryGetValue(w, out var f) ? f : 0);

        return score;
    }

    private static List<string> Tokenize(string text) =>
        WordRegex().Matches(text).Select(m => m.Value).ToList();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummaryService summaryService) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

